prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?elem ?name ?type WHERE {
  ?model a bboExt:Model ;
         tai:originalId "262d9e9b8c224d918fe800cd2a454ddf" .
  ?def tai:belongsTo ?model .
  ?choreo tai:belongsTo ?def .
  ?elem tai:belongsTo ?choreo ;
        a ?type .
  OPTIONAL { ?elem bbo:name ?name . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?elem ?type ?name WHERE {
  ?model a bboExt:Model ;
         tai:originalId "262d9e9b8c224d918fe800cd2a454ddf" .
  ?def tai:belongsTo ?model .
  ?choreo tai:belongsTo ?def .
  ?elem tai:belongsTo ?choreo ;
        a ?type .
  OPTIONAL { ?elem bbo:name ?name . }
  FILTER(?type IN (bboExt:ChoreographyTask, bboExt:ExclusiveGateway, bboExt:ParallelGateway, bboExt:StartEvent, bboExt:EndEvent))
  FILTER(!BOUND(?name) || ?name = "")
}
